code.javascript:
function majorityElement(nums) {
  const counts = {};
  for (const n of nums) {
    counts[n] = (counts[n] || 0) + 1;
    if (counts[n] > Math.floor(nums.length / 2)) {
      return n;
    }
  }
  return nums[0];
}

code.typescript:
function majorityElement(nums: number[]): number {
  const counts: Record<number, number> = {};
  for (const n of nums) {
    counts[n] = (counts[n] || 0) + 1;
    if (counts[n] > Math.floor(nums.length / 2)) {
      return n;
    }
  }
  return nums[0];
}
